DROP TABLE IF EXISTS `adopt`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `adopt` (
  `adopt_id` varchar(50) NOT NULL,
  `animal_id` varchar(32) NOT NULL COMMENT '宠物ID',
  `name` varchar(50) NOT NULL COMMENT '申请人姓名',
  `phone` varchar(20) NOT NULL COMMENT '联系电话',
  `email` varchar(100) DEFAULT NULL COMMENT '电子邮箱',
  `address` varchar(200) DEFAULT NULL COMMENT '居住地址',
  `occupation` varchar(50) DEFAULT NULL COMMENT '职业',
  `reason` text COMMENT '申请理由',
  `pet_experience` varchar(20) DEFAULT NULL COMMENT '宠物经验',
  `status` varchar(20) DEFAULT '审核中',
  `description` text COMMENT '处理说明',
  `user_id` int DEFAULT NULL COMMENT '申请用户ID',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '申请时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`adopt_id`),
  KEY `idx_animal_id` (`animal_id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='领养申请表';
